+            ("overhead_ratio".to_string(), format!("{:.2}", overhead_ratio)),
+        ]
+        .into_iter()
+        .collect(),
+    })
+}
+
+fn bench_quantization_memory(args: &Args) -> Result<Vec<BenchmarkResult>> {
+    let quantizations = vec![
