+                },
+                memory: format!("{:.2}", r.memory_mb),
+                per_vector,
+                build_time: format!("{:.2}", r.build_time_secs),
+            }
+        })
+        .collect();
+
+    println!("\n\n{}", Table::new(rows));
+}

