+            let vec: Vec<f32> = (0..128).map(|j| (i + j) as f32 / 128.0).collect();
+            index.insert(i, vec);
+        }
+
+        let ratio = index.compression_ratio();
+        assert!(ratio > 1.0); // Should have compression
+    }
+}

