+/// Hybrid search combining vector and keyword matching
+#[derive(Debug, Clone)]
+pub struct HybridSearch {
+    /// Configuration
+    pub config: HybridConfig,
+    /// BM25 index for keyword matching
+    pub bm25: BM25,
+    /// Document texts for BM25 scoring
+    pub doc_texts: HashMap<VectorId, String>,
