+impl HybridSearch {
+    /// Create a new hybrid search instance
+    pub fn new(config: HybridConfig) -> Self {
+        Self {
+            config,
+            bm25: BM25::new(1.5, 0.75), // Standard BM25 parameters
+            doc_texts: HashMap::new(),
